example.code:
{
  "identifier": "service",
  "title": "Service",
  "icon": "Microservice",
  "schema": {
    "properties": {
      "name": {
        "type": "string",
        "title": "Service Name"
      },
      "description": {
        "type": "string",
        "title": "Description"
      },
      "owner": {
        "type": "string",
        "title": "Owner Team"
      },
      "tier": {
        "type": "string",
        "title": "Service Tier",
        "enum": ["critical", "standard", "experimental"]
      },
      "language": {
        "type": "string",
        "title": "Language",
        "enum": ["go", "python", "typescript", "java", "rust"]
      },
      "repository": {
        "type": "string",
        "format": "url",
        "title": "Repository URL"
      },
      "deploymentFrequency": {
        "type": "number",
        "title": "Deployments per Week"
      }
    }
  }
}

{
  "dashboard": {
    "title": "Platform Health",
    "panels": [
      {
        "title": "Self-Service Adoption",
        "type": "stat",
        "targets": [{
          "expr": "sum(platform_self_service_requests_total) / sum(platform_ticket_requests_total) * 100"
        }]
      },
      {
        "title": "Deployment Frequency",
        "type": "timeseries",
        "targets": [{
          "expr": "sum(rate(deployments_total[1d])) by (team)"
        }]
      },
      {
        "title": "Lead Time for Changes",
        "type": "gauge",
        "targets": [{
          "expr": "histogram_quantile(0.50, sum(rate(lead_time_seconds_bucket[7d])) by (le))"
        }]
      },
      {
        "title": "Platform Cost by Team",
        "type": "piechart",
        "targets": [{
          "expr": "sum(cloud_cost_daily) by (team)"
        }]
      },
      {
        "title": "Change Failure Rate",
        "type": "timeseries",
        "targets": [{
          "expr": "sum(rate(failed_deployments_total[1d])) / sum(rate(deployments_total[1d]))"
        }]
      }
    ]
  }
}

# .github/workflows/deploy.yaml jobs: cost-check: runs-on: ubuntu-latest steps: - uses: actions/checkout@v4
- uses: infracost/actions/setup@v2 with: api-key: ${{ secrets.INFRACOST_API_KEY }}
- name: Generate Cost Diff run: | infracost diff \ --path=terraform/ \ --format=json \ --out-file=/tmp/infracost.json
- name: Check Cost Threshold run: | MONTHLY_DIFF=$(jq '.totalMonthlyCost' /tmp/infracost.json) if (( $(echo "$MONTHLY_DIFF > 500" | bc -l) )); then echo "Cost increase exceeds $500/month threshold" exit 1 fi
- name: Comment on PR uses: infracost/actions/comment@v1 with: path: /tmp/infracost.json github-token: ${{ secrets.GITHUB_TOKEN }}
